#include <bits/stdc++.h>
using namespace std;
struct war{
    int l,r;
}a[100005];
bool cmp(war x,war y){
    if(x.r==y.r)return x.l<=y.l;
    return x.r<y.r;
}
int main(){
    int n,m;
    cin>>n>>m;
    for(int i=1;i<=m;i++)cin>>a[i].l>>a[i].r;
    sort(a+1,a+m+1,cmp);
    int ans=1,zt=a[1].r-1;
    for(int i=2;i<=m;i++){
        if(a[i].l>zt){
            zt=a[i].r-1;
            ans++;
        }
    }
    cout<<ans;
    return 0;
}
